import { useState, useEffect, useCallback } from "react";
import { SectionLabel, Spinner } from "./UI";

// ── Sentiment Analysis ─────────────────────────────────────
// Simple keyword-based sentiment scorer.
// In production you'd use a proper NLP API (e.g. Finnhub).
const POSITIVE_WORDS = [
  "beat","surge","rally","growth","profit","record","upgrade","buy",
  "strong","gain","rise","higher","outperform","bullish","positive",
  "exceed","revenue","earnings","dividend","acquisition","expansion",
  "partnership","innovative","breakthrough","optimistic","recovery",
];
const NEGATIVE_WORDS = [
  "miss","drop","fall","loss","decline","downgrade","sell","weak",
  "lower","underperform","bearish","negative","warning","risk","debt",
  "lawsuit","investigation","recall","layoff","cut","bankruptcy","fraud",
  "concern","disappointing","shortfall","headwind","volatile","crash",
];

function scoreSentiment(text) {
  const lower = text.toLowerCase();
  let score   = 0;
  POSITIVE_WORDS.forEach(w => { if (lower.includes(w)) score += 1; });
  NEGATIVE_WORDS.forEach(w => { if (lower.includes(w)) score -= 1; });
  if (score >  1) return { label: "POSITIVE", color: "#00ff9d", score };
  if (score < -1) return { label: "NEGATIVE", color: "#ff6b35", score };
  return               { label: "NEUTRAL",  color: "#ffd700",  score };
}

// ── Free news sources (no API key needed) ──────────────────
// 1. Finnhub free tier — company news
// 2. GNews API free tier — general news search
// 3. Yahoo Finance RSS via CORS proxy as fallback

const CORS = "https://corsproxy.io/?";

async function fetchFinnhubNews(ticker) {
  const to   = new Date().toISOString().slice(0, 10);
  const from = new Date(Date.now() - 7 * 24 * 3600 * 1000).toISOString().slice(0, 10);
  const url  = `https://finnhub.io/api/v1/company-news?symbol=${ticker}&from=${from}&to=${to}&token=demo`;
  const res  = await fetch(url);
  if (!res.ok) throw new Error(`Finnhub ${res.status}`);
  const data = await res.json();
  if (!Array.isArray(data)) throw new Error("No data");
  return data.slice(0, 8).map(a => ({
    id:       a.id,
    title:    a.headline,
    summary:  a.summary,
    source:   a.source,
    url:      a.url,
    time:     new Date(a.datetime * 1000).toLocaleDateString(),
    image:    a.image || null,
  }));
}

async function fetchYahooRSS(ticker) {
  const rssUrl = `https://feeds.finance.yahoo.com/rss/2.0/headline?s=${ticker}&region=US&lang=en-US`;
  const res    = await fetch(`${CORS}${encodeURIComponent(rssUrl)}`);
  if (!res.ok) throw new Error(`Yahoo RSS ${res.status}`);
  const text   = await res.text();
  const parser = new DOMParser();
  const xml    = parser.parseFromString(text, "text/xml");
  const items  = Array.from(xml.querySelectorAll("item")).slice(0, 10);
  return items.map((item, i) => ({
    id:      i,
    title:   item.querySelector("title")?.textContent ?? "",
    summary: item.querySelector("description")?.textContent?.replace(/<[^>]+>/g, "") ?? "",
    source:  "Yahoo Finance",
    url:     item.querySelector("link")?.textContent ?? "#",
    time:    (() => {
      const d = item.querySelector("pubDate")?.textContent;
      return d ? new Date(d).toLocaleDateString() : "";
    })(),
    image:   null,
  })).filter(a => a.title);
}

async function fetchNewsForTicker(ticker) {
  // Try Finnhub first, fall back to Yahoo RSS
  try {
    const articles = await fetchFinnhubNews(ticker);
    if (articles.length > 0) return { articles, source: "Finnhub" };
  } catch (e) {
    console.warn(`Finnhub failed for ${ticker}:`, e.message);
  }
  try {
    const articles = await fetchYahooRSS(ticker);
    if (articles.length > 0) return { articles, source: "Yahoo Finance RSS" };
  } catch (e) {
    console.warn(`Yahoo RSS failed for ${ticker}:`, e.message);
  }
  return { articles: [], source: null };
}

// ── Sentiment gauge component ──────────────────────────────
function SentimentGauge({ positive, neutral, negative, total }) {
  const pPct = total ? (positive / total) * 100 : 0;
  const nPct = total ? (neutral  / total) * 100 : 0;
  const gPct = total ? (negative / total) * 100 : 0;
  const overallScore = total ? ((positive - negative) / total) * 100 : 0;
  const overallColor = overallScore > 20 ? "#00ff9d" : overallScore < -20 ? "#ff6b35" : "#ffd700";
  const overallLabel = overallScore > 20 ? "BULLISH" : overallScore < -20 ? "BEARISH" : "NEUTRAL";

  return (
    <div style={{ background: "#0d1117", border: "1px solid #1c2333", borderRadius: 6, padding: "14px 16px" }}>
      <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", marginBottom: 10 }}>
        <span style={{ color: "#8b949e", fontSize: 11, letterSpacing: "0.08em" }}>SENTIMENT SCORE</span>
        <span style={{ color: overallColor, fontWeight: 700, fontSize: 13, letterSpacing: "0.1em" }}>{overallLabel}</span>
      </div>
      {/* Stacked bar */}
      <div style={{ height: 8, borderRadius: 4, overflow: "hidden", display: "flex", marginBottom: 8 }}>
        <div style={{ width: `${pPct}%`, background: "#00ff9d", transition: "width 0.5s" }} />
        <div style={{ width: `${nPct}%`, background: "#ffd700", transition: "width 0.5s" }} />
        <div style={{ width: `${gPct}%`, background: "#ff6b35", transition: "width 0.5s" }} />
      </div>
      <div style={{ display: "flex", justifyContent: "space-between", fontSize: 10, color: "#8b949e" }}>
        <span style={{ color: "#00ff9d" }}>▲ {positive} positive</span>
        <span style={{ color: "#ffd700" }}>{neutral} neutral</span>
        <span style={{ color: "#ff6b35" }}>▼ {negative} negative</span>
      </div>
    </div>
  );
}

// ── Article card ───────────────────────────────────────────
function ArticleCard({ article }) {
  const sentiment = scoreSentiment(article.title + " " + article.summary);
  return (
    <a
      href={article.url}
      target="_blank"
      rel="noreferrer"
      style={{ textDecoration: "none", display: "block" }}
    >
      <div
        style={{
          padding: "12px 14px",
          borderBottom: "1px solid #0d1117",
          transition: "background 0.1s",
          borderLeft: `3px solid ${sentiment.color}`,
        }}
        onMouseEnter={e => e.currentTarget.style.background = "#00ff9d06"}
        onMouseLeave={e => e.currentTarget.style.background = "transparent"}
      >
        <div style={{ display: "flex", justifyContent: "space-between", alignItems: "flex-start", gap: 10, marginBottom: 5 }}>
          <span style={{ color: "#c9d1d9", fontSize: 12, fontWeight: 500, lineHeight: 1.5, flex: 1 }}>
            {article.title}
          </span>
          <span style={{
            background: sentiment.color + "18",
            color: sentiment.color,
            border: `1px solid ${sentiment.color}33`,
            padding: "1px 7px", borderRadius: 3,
            fontSize: 9, letterSpacing: "0.08em", whiteSpace: "nowrap",
          }}>
            {sentiment.label}
          </span>
        </div>
        {article.summary && (
          <p style={{ color: "#8b949e", fontSize: 11, lineHeight: 1.6, marginBottom: 6 }}>
            {article.summary.slice(0, 140)}{article.summary.length > 140 ? "…" : ""}
          </p>
        )}
        <div style={{ display: "flex", gap: 12, fontSize: 10, color: "#8b949e44" }}>
          <span style={{ color: "#8b949e" }}>{article.source}</span>
          <span>{article.time}</span>
        </div>
      </div>
    </a>
  );
}

// ── Portfolio sentiment summary ────────────────────────────
function PortfolioSentimentBar({ sentimentMap, holdings }) {
  const items = holdings
    .map(h => ({ ...h, sentiment: sentimentMap[h.ticker] }))
    .filter(h => h.sentiment);

  if (!items.length) return null;

  const avgScore = items.reduce((s, h) => {
    const { positive, negative, total } = h.sentiment;
    return s + (total ? (positive - negative) / total : 0);
  }, 0) / items.length;

  const overallColor = avgScore > 0.2 ? "#00ff9d" : avgScore < -0.2 ? "#ff6b35" : "#ffd700";
  const overallLabel = avgScore > 0.2 ? "PORTFOLIO BULLISH" : avgScore < -0.2 ? "PORTFOLIO BEARISH" : "PORTFOLIO NEUTRAL";

  return (
    <div style={{
      background: "#0d1117", border: `1px solid ${overallColor}33`,
      borderRadius: 6, padding: "14px 16px", marginBottom: 20,
    }}>
      <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", marginBottom: 12 }}>
        <span style={{ color: "#8b949e", fontSize: 11, letterSpacing: "0.08em" }}>PORTFOLIO-WIDE SENTIMENT</span>
        <span style={{ color: overallColor, fontWeight: 700, fontSize: 13, letterSpacing: "0.1em" }}>{overallLabel}</span>
      </div>
      <div style={{ display: "flex", gap: 8, flexWrap: "wrap" }}>
        {items.map(h => {
          const { positive, negative, total } = h.sentiment;
          const score  = total ? (positive - negative) / total : 0;
          const color  = score > 0.15 ? "#00ff9d" : score < -0.15 ? "#ff6b35" : "#ffd700";
          const label  = score > 0.15 ? "▲" : score < -0.15 ? "▼" : "–";
          return (
            <div key={h.ticker} style={{
              background: color + "12", border: `1px solid ${color}33`,
              borderRadius: 4, padding: "6px 10px", textAlign: "center",
            }}>
              <div style={{ color, fontWeight: 700, fontSize: 12 }}>{label} {h.ticker}</div>
              <div style={{ color: "#8b949e", fontSize: 9, marginTop: 2 }}>{total} articles</div>
            </div>
          );
        })}
      </div>
    </div>
  );
}

// ── Main component ─────────────────────────────────────────
export default function NewsSentiment({ holdings }) {
  const [selectedTicker, setSelectedTicker] = useState(holdings[0]?.ticker ?? null);
  const [newsCache,      setNewsCache]      = useState({});   // { ticker: { articles, source } }
  const [sentimentMap,   setSentimentMap]   = useState({});   // { ticker: { positive, neutral, negative, total } }
  const [loading,        setLoading]        = useState(false);
  const [error,          setError]          = useState(null);

  const loadNews = useCallback(async (ticker) => {
    if (newsCache[ticker]) return; // already loaded
    setLoading(true);
    setError(null);
    try {
      const { articles, source } = await fetchNewsForTicker(ticker);
      setNewsCache(prev => ({ ...prev, [ticker]: { articles, source } }));

      // Compute sentiment counts
      const counts = articles.reduce((acc, a) => {
        const s = scoreSentiment(a.title + " " + a.summary);
        acc[s.label.toLowerCase()] = (acc[s.label.toLowerCase()] || 0) + 1;
        return acc;
      }, { positive: 0, neutral: 0, negative: 0 });

      setSentimentMap(prev => ({
        ...prev,
        [ticker]: { ...counts, total: articles.length },
      }));
    } catch (e) {
      setError(`Failed to load news for ${ticker}: ${e.message}`);
    } finally {
      setLoading(false);
    }
  }, [newsCache]);

  // Load news when ticker changes
  useEffect(() => {
    if (selectedTicker) loadNews(selectedTicker);
  }, [selectedTicker, loadNews]);

  // Pre-load all holdings in background for portfolio summary
  useEffect(() => {
    holdings.forEach(h => {
      setTimeout(() => loadNews(h.ticker), 500);
    });
  // eslint-disable-next-line
  }, []);

  if (!holdings.length) {
    return <p style={{ color: "#8b949e", padding: 40, textAlign: "center" }}>Add holdings to view news.</p>;
  }

  const current   = newsCache[selectedTicker];
  const sentiment = sentimentMap[selectedTicker];

  return (
    <div>
      <SectionLabel>News & Sentiment Feed</SectionLabel>

      {/* Portfolio-wide sentiment summary */}
      <PortfolioSentimentBar sentimentMap={sentimentMap} holdings={holdings} />

      <div style={{ display: "grid", gridTemplateColumns: "220px 1fr", gap: 20 }}>

        {/* ── Stock selector ──────────────────────────── */}
        <div>
          <p style={{ color: "#8b949e", fontSize: 11, letterSpacing: "0.08em", marginBottom: 10 }}>SELECT HOLDING</p>
          <div style={{ background: "#0d1117", border: "1px solid #1c2333", borderRadius: 6, overflow: "hidden" }}>
            {holdings.map(h => {
              const s     = sentimentMap[h.ticker];
              const score = s ? (s.positive - s.negative) / (s.total || 1) : null;
              const color = score === null ? "#8b949e"
                : score >  0.15 ? "#00ff9d"
                : score < -0.15 ? "#ff6b35"
                : "#ffd700";
              const icon  = score === null ? "…"
                : score >  0.15 ? "▲"
                : score < -0.15 ? "▼"
                : "–";

              return (
                <div
                  key={h.ticker}
                  onClick={() => setSelectedTicker(h.ticker)}
                  style={{
                    padding: "10px 12px",
                    borderBottom: "1px solid #0d1117",
                    cursor: "pointer",
                    background: selectedTicker === h.ticker ? "#00ff9d0d" : "transparent",
                    borderLeft: `2px solid ${selectedTicker === h.ticker ? "#00ff9d" : "transparent"}`,
                    display: "flex", justifyContent: "space-between", alignItems: "center",
                    transition: "all 0.1s",
                  }}
                >
                  <div>
                    <span className="ticker-tag" style={{ marginRight: 6 }}>{h.ticker}</span>
                    <span style={{ color: "#8b949e", fontSize: 10 }}>{s ? `${s.total} articles` : ""}</span>
                  </div>
                  <span style={{ color, fontWeight: 700, fontSize: 12 }}>{icon}</span>
                </div>
              );
            })}
          </div>
        </div>

        {/* ── News feed ───────────────────────────────── */}
        <div>
          {/* Sentiment gauge for selected ticker */}
          {sentiment && (
            <div style={{ marginBottom: 16 }}>
              <SentimentGauge
                positive={sentiment.positive}
                neutral={sentiment.neutral}
                negative={sentiment.negative}
                total={sentiment.total}
              />
            </div>
          )}

          {/* News source tag */}
          {current?.source && (
            <div style={{ marginBottom: 10, display: "flex", alignItems: "center", gap: 8 }}>
              <span style={{ color: "#8b949e", fontSize: 11 }}>Source:</span>
              <span style={{ background: "#00ff9d12", color: "#00ff9d", border: "1px solid #00ff9d33", padding: "1px 8px", borderRadius: 3, fontSize: 11 }}>
                {current.source}
              </span>
              <button
                onClick={() => {
                  setNewsCache(prev => { const n = {...prev}; delete n[selectedTicker]; return n; });
                  setSentimentMap(prev => { const n = {...prev}; delete n[selectedTicker]; return n; });
                  loadNews(selectedTicker);
                }}
                style={{ marginLeft: "auto", cursor: "pointer", background: "transparent", border: "1px solid #1c2333", color: "#8b949e", padding: "3px 10px", borderRadius: 3, fontFamily: "inherit", fontSize: 11 }}
              >
                ↻ REFRESH
              </button>
            </div>
          )}

          {/* Articles */}
          <div style={{ background: "#0d1117", border: "1px solid #1c2333", borderRadius: 6, overflow: "hidden" }}>
            {loading && !current && (
              <div style={{ padding: 40, textAlign: "center" }}>
                <Spinner />
                <p style={{ color: "#8b949e", fontSize: 12, marginTop: 10 }}>Fetching news for {selectedTicker}…</p>
              </div>
            )}

            {error && (
              <div style={{ padding: "12px 16px", color: "#ff6b35", fontSize: 12 }}>⚠ {error}</div>
            )}

            {current?.articles.length === 0 && !loading && (
              <div style={{ padding: 40, textAlign: "center", color: "#8b949e" }}>
                No recent articles found for {selectedTicker}.
              </div>
            )}

            {current?.articles.map(a => (
              <ArticleCard key={a.id} article={a} />
            ))}
          </div>

          {/* Disclaimer */}
          <p style={{ color: "#8b949e44", fontSize: 10, marginTop: 10 }}>
            Sentiment scored by keyword analysis. Not financial advice. News sourced from Finnhub / Yahoo Finance RSS.
          </p>
        </div>
      </div>
    </div>
  );
}
